{"meta": null, "content": [{"type": "text", "text": "{"content":"300: \t\tf.enqueueExtensions = []framework.EnqueueExtensions{\u0026defaultEnqueueExtension{pluginName: framework.ExtenderName}}\n301: \t}\n302: \n303: \tif profile == nil {\n304: \t\treturn f, nil\n305: \t}\n306: \n307: \tf.profileName = profile.SchedulerName\n308: \tf.percentageOfNodesToScore = profile.PercentageOfNodesToScore\n309: \tif profile.Plugins == nil {\n310: \t\treturn f, nil\n311: \t}\n312: \n313: \t// get needed plugins from config\n314: \tpg := f.pluginsNeeded(profile.Plugins)\n315: \n316: \tpluginConfig := make(map[string]runtime.Object, len(profile.PluginConfig))\n317: \tfor i := range profile.PluginConfig {\n318: \t\tname := profile.PluginConfig[i].Name\n319: \t\tif _, ok := pluginConfig[name]; ok {\n320: \t\t\treturn nil, fmt.Errorf(\"repeated config for plugin %s\", name)\n321: \t\t}\n322: \t\tpluginConfig[name] = profile.PluginConfig[i].Args\n323: \t}\n324: \toutputProfile := config.KubeSchedulerProfile{\n325: \t\tSchedulerName:            f.profileName,\n326: \t\tPercentageOfNodesToScore: f.percentageOfNodesToScore,\n327: \t\tPlugins:                  profile.Plugins,\n328: \t\tPluginConfig:             make([]config.PluginConfig, 0, len(pg)),\n329: \t}\n330: \n331: \tf.pluginsMap = make(map[string]framework.Plugin)\n332: \tfor name, factory := range r {\n333: \t\t// initialize only needed plugins.\n334: \t\tif !pg.Has(name) {\n335: \t\t\tcontinue\n336: \t\t}\n337: \n338: \t\targs := pluginConfig[name]\n339: \t\tif args != nil {\n340: \t\t\toutputProfile.PluginConfig = append(outputProfile.PluginConfig, config.PluginConfig{\n341: \t\t\t\tName: name,\n342: \t\t\t\tArgs: args,\n343: \t\t\t})\n344: \t\t}\n345: \t\tp, err := factory(ctx, args, f)\n346: \t\tif err != nil {\n347: \t\t\treturn nil, fmt.Errorf(\"initializing plugin %q: %w\", name, err)\n348: \t\t}\n349: \t\tf.pluginsMap[name] = p\n350: \n351: \t\tf.fillEnqueueExtensions(p)\n352: \t}\n353: \n354: \t// initialize plugins per individual extension points\n355: \tfor _, e := range f.getExtensionPoints(profile.Plugins) {\n356: \t\tif err := updatePluginList(e.slicePtr, *e.plugins, f.pluginsMap); err != nil {\n357: \t\t\treturn nil, err\n358: \t\t}\n359: \t}\n360: \n361: \t// initialize multiPoint plugins to their expanded extension points\n362: \tif len(profile.Plugins.MultiPoint.Enabled) \u003e 0 {\n363: \t\tif err := f.expandMultiPointPlugins(logger, profile); err != nil {\n364: \t\t\treturn nil, err\n365: \t\t}\n366: \t}\n367: \n368: \tif len(f.queueSortPlugins) != 1 {\n369: \t\treturn nil, fmt.Errorf(\"only one queue sort plugin required for profile with scheduler name %q, but got %d\", profile.SchedulerName, len(f.queueSortPlugins))\n370: \t}\n371: \tif len(f.bindPlugins) == 0 {\n372: \t\treturn nil, fmt.Errorf(\"at least one bind plugin is needed for profile with scheduler name %q\", profile.SchedulerName)\n373: \t}\n374: \n375: \tif err := getScoreWeights(f, append(profile.Plugins.Score.Enabled, profile.Plugins.MultiPoint.Enabled...)); err != nil {\n376: \t\treturn nil, err\n377: \t}\n378: \n379: \t// Verifying the score weights again since Plugin.Name() could return a different\n380: \t// value from the one used in the configuration.\n381: \tfor _, scorePlugin := range f.scorePlugins {\n382: \t\tif f.scorePluginWeight[scorePlugin.Name()] == 0 {\n383: \t\t\treturn nil, fmt.Errorf(\"score plugin %q is not configured with weight\", scorePlugin.Name())\n384: \t\t}\n385: \t}\n386: \n387: \tif options.captureProfile != nil {\n388: \t\tif len(outputProfile.PluginConfig) != 0 {\n389: \t\t\tsort.Slice(outputProfile.PluginConfig, func(i, j int) bool {\n390: \t\t\t\treturn outputProfile.PluginConfig[i].Name \u003c outputProfile.PluginConfig[j].Name\n391: \t\t\t})\n392: \t\t} else {\n393: \t\t\toutputProfile.PluginConfig = nil\n394: \t\t}\n395: \t\toptions.captureProfile(outputProfile)\n396: \t}\n397: \n398: \t// Logs Enabled Plugins at each extension point, taking default plugins, given config, and multipoint into consideration\n399: \tlogger.V(2).Info(\"the scheduler starts to work with those plugins\", \"Plugins\", *f.ListPlugins())\n400: \tf.setInstrumentedPlugins()\n401: \treturn f, nil\n402: }\n403: \n404: // setInstrumentedPlugins initializes instrumented plugins from current plugins that frameworkImpl has.\n405: func (f *frameworkImpl) setInstrumentedPlugins() {\n406: \t// Cache metric streams for prefilter and filter plugins.\n407: \tfor i, pl := range f.preFilterPlugins {\n408: \t\tf.preFilterPlugins[i] = \u0026instrumentedPreFilterPlugin{\n409: \t\t\tPreFilterPlugin: f.preFilterPlugins[i],\n410: \t\t\tmetric:          metrics.PluginEvaluationTotal.WithLabelValues(pl.Name(), metrics.PreFilter, f.profileName),\n411: \t\t}\n412: \t}\n413: \tfor i, pl := range f.filterPlugins {\n414: \t\tf.filterPlugins[i] = \u0026instrumentedFilterPlugin{\n415: \t\t\tFilterPlugin: f.filterPlugins[i],\n416: \t\t\tmetric:       metrics.PluginEvaluationTotal.WithLabelValues(pl.Name(), metrics.Filter, f.profileName),\n417: \t\t}\n418: \t}\n419: \n420: \t// Cache metric streams for prescore and score plugins.\n421: \tfor i, pl := range f.preScorePlugins {\n422: \t\tf.preScorePlugins[i] = \u0026instrumentedPreScorePlugin{\n423: \t\t\tPreScorePlugin: f.preScorePlugins[i],\n424: \t\t\tmetric:         metrics.PluginEvaluationTotal.WithLabelValues(pl.Name(), metrics.PreScore, f.profileName),\n425: \t\t}\n426: \t}\n427: \tfor i, pl := range f.scorePlugins {\n428: \t\tf.scorePlugins[i] = \u0026instrumentedScorePlugin{\n429: \t\t\tScorePlugin: f.scorePlugins[i],\n430: \t\t\tmetric:      metrics.PluginEvaluationTotal.WithLabelValues(pl.Name(), metrics.Score, f.profileName),\n431: \t\t}\n432: \t}\n433: }\n434: \n435: func (f *frameworkImpl) SetPodNominator(n framework.PodNominator) {\n436: \tf.PodNominator = n\n437: }\n438: \n439: func (f *frameworkImpl) SetPodActivator(a framework.PodActivator) {\n440: \tf.PodActivator = a\n441: }\n442: \n443: // Close closes each plugin, when they implement io.Closer interface.\n444: func (f *frameworkImpl) Close() error {\n445: \tvar errs []error\n446: \tfor name, plugin := range f.pluginsMap {\n447: \t\tif closer, ok := plugin.(io.Closer); ok {\n448: \t\t\terr := closer.Close()\n449: \t\t\tif err != nil {\n450: \t\t\t\terrs = append(errs, fmt.Errorf(\"%s failed to close: %w\", name, err))\n451: \t\t\t\t// We try to close all plugins even if we got errors from some.\n452: \t\t\t}\n453: \t\t}\n454: \t}\n455: \treturn errors.Join(errs...)\n456: }\n457: \n458: // getScoreWeights makes sure that, between MultiPoint-Score plugin weights and individual Score\n459: // plugin weights there is not an overflow of MaxTotalScore.\n460: func getScoreWeights(f *frameworkImpl, plugins []config.Plugin) error {\n461: \tvar totalPriority int64\n462: \tscorePlugins := reflect.ValueOf(\u0026f.scorePlugins).Elem()\n463: \tpluginType := scorePlugins.Type().Elem()\n464: \tfor _, e := range plugins {\n465: \t\tpg := f.pluginsMap[e.Name]\n466: \t\tif !reflect.TypeOf(pg).Implements(pluginType) {\n467: \t\t\tcontinue\n468: \t\t}\n469: \n470: \t\t// We append MultiPoint plugins to the list of Score plugins. So if this plugin has already been\n471: \t\t// encountered, let the individual Score weight take precedence.\n472: \t\tif _, ok := f.scorePluginWeight[e.Name]; ok {\n473: \t\t\tcontinue\n474: \t\t}\n475: \t\t// a weight of zero is not permitted, plugins can be disabled explicitly\n476: \t\t// when configured.\n477: \t\tf.scorePluginWeight[e.Name] = int(e.Weight)\n478: \t\tif f.scorePluginWeight[e.Name] == 0 {\n479: \t\t\tf.scorePluginWeight[e.Name] = 1\n480: \t\t}\n481: \n482: \t\t// Checks totalPriority against MaxTotalScore to avoid overflow\n483: \t\tif int64(f.scorePluginWeight[e.Name])*framework.MaxNodeScore \u003e framework.MaxTotalScore-totalPriority {\n484: \t\t\treturn fmt.Errorf(\"total score of Score plugins could overflow\")\n485: \t\t}\n486: \t\ttotalPriority += int64(f.scorePluginWeight[e.Name]) * framework.MaxN