443: // Close closes each plugin, when they implement io.Closer interface.
444: func (f *frameworkImpl) Close() error {
445: 	var errs []error
446: 	for name, plugin := range f.pluginsMap {
447: 		if closer, ok := plugin.(io.Closer); ok {
448: 			err := closer.Close()
449: 			if err != nil {
450: 				errs = append(errs, fmt.Errorf("%s failed to close: %w", name, err))
451: 				// We try to close all plugins even if we got errors from some.
452: 			}
453: 		}
454: 	}
455: 	return errors.Join(errs...)
456: }
