515: 	if i, found := os.set[s]; found {
516: 		delete(os.set, s)
517: 		os.list = append(os.list[:i-os.deletionCnt], os.list[i+1-os.deletionCnt:]...)
518: 		os.deletionCnt++
519: 	}
520: }
