528: 		// to check double registration
529: 		enabledSet := newOrderedSet()
530: 		for _, plugin := range e.plugins.Enabled {
531: 			enabledSet.insert(plugin.Name)
532: 		}
533: 
534: 		disabledSet := sets.New[string]()
535: 		for _, disabledPlugin := range e.plugins.Disabled {
536: 			disabledSet.Insert(disabledPlugin.Name)
537: 		}
