543: 		// track plugins enabled via multipoint separately from those enabled by specific extensions,
544: 		// so that we can distinguish between double-registration and explicit overrides
545: 		multiPointEnabled := newOrderedSet()
546: 		overridePlugins := newOrderedSet()
547: 		for _, ep := range profile.Plugins.MultiPoint.Enabled {
548: 			pg, ok := f.pluginsMap[ep.Name]
549: 			if !ok {
550: 				return fmt.Errorf("%s %q does not exist", pluginType.Name(), ep.Name)
551: 			}
552: 
553: 			// if this plugin doesn't implement the type for the current extension we're trying to expand, skip
554: 			if !reflect.TypeOf(pg).Implements(pluginType) {
555: 				continue
556: 			}
557: 
558: 			// a plugin that's enabled via MultiPoint can still be disabled for specific extension points
559: 			if disabledSet.Has(ep.Name) {
560: 				logger.V(4).Info("Skipped disabled plugin for extension point", "plugin", ep.Name, "extension", pluginType)
561: 				continue
562: 			}
563: 
564: 			// if this plugin has already been enabled by the specific extension point,
565: 			// the user intent is to override the default plugin or make some other explicit setting.
566: 			// Either way, discard the MultiPoint value for this plugin.
567: 			// This maintains expected behavior for overriding default plugins (see https://github.com/kubernetes/kubernetes/pull/99582)
568: 			if enabledSet.has(ep.Name) {
569: 				overridePlugins.insert(ep.Name)
570: 				logger.Info("MultiPoint plugin is explicitly re-configured; overriding", "plugin", ep.Name)
571: 				continue
572: 			}
573: 
574: 			// if this plugin is already registered via MultiPoint, then this is
575: 			// a double registration and an error in the config.
576: 			if multiPointEnabled.has(ep.Name) {
577: 				return fmt.Errorf("plugin %q already registered as %q", ep.Name, pluginType.Name())
578: 			}
579: 
580: 			// we only need to update the multipoint set, since we already have the specific extension set from above
581: 			multiPointEnabled.insert(ep.Name)
