609: func shouldHaveEnqueueExtensions(p framework.Plugin) bool {
610: 	switch p.(type) {
611: 	// Only PreEnqueue, PreFilter, Filter, Reserve, and Permit plugins can (should) have EnqueueExtensions.
612: 	// See the comment of EnqueueExtensions for more detailed reason here.
613: 	case framework.PreEnqueuePlugin, framework.PreFilterPlugin, framework.FilterPlugin, framework.ReservePlugin, framework.PermitPlugin:
614: 		return true
615: 	}
616: 	return false
